		const exited = new Promise<number>((r) => {
			resolveExit = r;
		});
		const result: SpawnResult = {
			pid: 1234,
			stdout,
			stderr,
			exited,
			cancel: () => resolveExit(130),
		};
		queueMicrotask(() => resolveExit(opts.exitCode ?? 0));
		return result;
	};
}

